17: package org.apache.camel.component.direct;
18: 
19: import java.util.HashMap;
20: import java.util.Map;
21: import java.util.concurrent.TimeUnit;
22: import java.util.concurrent.locks.Condition;
23: import java.util.concurrent.locks.Lock;
24: import java.util.concurrent.locks.ReentrantLock;
25: 
26: import org.apache.camel.Endpoint;
27: import org.apache.camel.spi.Metadata;
28: import org.apache.camel.spi.annotations.Component;
29: import org.apache.camel.support.DefaultComponent;
30: import org.apache.camel.support.service.ServiceHelper;
31: import org.apache.camel.util.StopWatch;
32: 
33: /**
34:  * The <a href="http://camel.apache.org/direct.html">Direct Component</a> manages {@link DirectEndpoint} and holds the
35:  * list of named direct endpoints.
36:  */
37: @Component("direct")
38: public class DirectComponent extends DefaultComponent {
39: 
40:     // active consumers
41:     private final Lock consumersLock = new ReentrantLock();
42:     private final Condition consumersCondition = consumersLock.newCondition();
43:     private final Map<String, DirectConsumer> consumers = new HashMap<>();
44:     // counter that is used for producers to keep track if any consumer was added/removed since they last checked
45:     // this is used for optimization to avoid each producer to get consumer for each message processed
46:     // (locking via synchronized, and then lookup in the map as the cost)
47:     // consumers and producers are only added/removed during startup/shutdown or if routes is manually controlled
48:     private volatile int stateCounter;
49: 
50:     @Metadata(label = "producer", defaultValue = "true")
51:     private boolean block = true;
52:     @Metadata(label = "producer", defaultValue = "30000")
53:     private long timeout = 30000L;
54: 
55:     public DirectComponent() {
56:     }
57: 
58:     @Override
59:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
60:         DirectEndpoint endpoint = new DirectEndpoint(uri, this);
61:         endpoint.setBlock(block);
62:         endpoint.setTimeout(timeout);
63:         setProperties(endpoint, parameters);
64:         return endpoint;
65:     }
66: 
67:     @Override
68:     protected void doShutdown() throws Exception {
69:         ServiceHelper.stopAndShutdownService(consumers);
70:         consumers.clear();
71:         super.doShutdown();
72:     }
73: 
74:     public boolean isBlock() {
75:         return block;
76:     }
77: 
78:     /**
79:      * If sending a message to a direct endpoint which has no active consumer, then we can tell the producer to block
80:      * and wait for the consumer to become active.
81:      */
82:     public void setBlock(boolean block) {
83:         this.block = block;
84:     }
85: 
86:     public long getTimeout() {
87:         return timeout;
88:     }
89: 
90:     /**
91:      * The timeout value to use if block is enabled.
92:      */
93:     public void setTimeout(long timeout) {
94:         this.timeout = timeout;
95:     }
96: 
97:     int getStateCounter() {
98:         return stateCounter;
99:     }
100: 
101:     public void addConsumer(String key, DirectConsumer consumer) {
102:         consumersLock.lock();
103:         try {
104:             if (consumers.putIfAbsent(key, consumer) != null) {
105:                 throw new IllegalArgumentException(
106:                         "Cannot add a 2nd consumer to the same endpoint: " + key
107:                                                    + ". DirectEndpoint only allows one consumer.");
108:             }
109:             // state changed so inc counter
110:             stateCounter++;
111:             consumersCondition.signalAll();
112:         } finally {
113:             consumersLock.unlock();
114:         }
115:     }
116: 
117:     public void removeConsumer(String key, DirectConsumer consumer) {
118:         consumersLock.lock();
119:         try {
120:             consumers.remove(key, consumer);
121:             // state changed so inc counter
122:             stateCounter++;
123:             consumersCondition.signalAll();
124:         } finally {
125:             consumersLock.unlock();
126:         }
127:     }
128: 
129:     protected DirectConsumer getConsumer(String key, boolean block, long timeout) throws InterruptedException {
130:         consumersLock.lock();
131:         try {
132:             DirectConsumer answer = consumers.get(key);
133:             if (answer == null && block) {
134:                 StopWatch watch = new StopWatch();
135:                 for (;;) {
136:                     answer = consumers.get(key);
137:                     if (answer != null) {
138:                         break;
139:                     }
140:                     long rem = timeout - watch.taken();
141:                     if (rem <= 0) {
142:                         break;
143:                     }
144:                     consumersCondition.await(rem, TimeUnit.MILLISECONDS);
145:                 }
146:             }
147:             return answer;
148:         } finally {
149:             consumersLock.unlock();
150:         }
151:     }
152: 
153: }
