package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * The FIX producer sends outbound FIX messages from Camel exchanges.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public void process(Exchange exchange) throws Exception {
        LOG.debug("Processing FIX message for session: {}", endpoint.getSessionID());
        // Extract the message from the exchange body and send it via FIX
        // The message would be sent to the configured FIX session
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            LOG.debug("Processing FIX message asynchronously for session: {}", endpoint.getSessionID());
            // Process the exchange asynchronously
            // Extract message and send via FIX
            callback.done(true);
            return true;
        } catch (Exception e) {
            exchange.setException(e);
            callback.done(true);
            return true;
        }
    }
}

